const fs = require('fs');
const path = require('path');

const basePath = 'C:\\Users\\LuizFerreira\\Projects';
const projects = [];

// Detecta tipo de projeto
const detectType = (dir) => {
  if (fs.existsSync(path.join(dir, 'wp-config.php'))) return 'wordpress';
  if (fs.existsSync(path.join(dir, 'next.config.js'))) return 'nextjs';
  if (fs.existsSync(path.join(dir, 'package.json'))) return 'nodejs';
  if (fs.existsSync(path.join(dir, 'composer.json'))) return 'php';
  if (fs.existsSync(path.join(dir, 'requirements.txt'))) return 'python';
  if (fs.existsSync(path.join(dir, 'go.mod'))) return 'go';
  if (fs.existsSync(path.join(dir, 'Cargo.toml'))) return 'rust';
  return 'unknown';
};

try {
  const dirs = fs.readdirSync(basePath);

  for (const dir of dirs) {
    const projectPath = path.join(basePath, dir);
    const stat = fs.statSync(projectPath);

    if (stat.isDirectory()) {
      const type = detectType(projectPath);
      const pkgPath = path.join(projectPath, 'package.json');
      let version = null;

      if (fs.existsSync(pkgPath)) {
        try {
          const pkg = JSON.parse(fs.readFileSync(pkgPath, 'utf-8'));
          version = pkg.version;
        } catch {}
      }

      projects.push({
        name: dir,
        path: projectPath,
        type,
        version,
        isValid: type !== 'unknown'
      });
    }
  }
} catch (e) {
  console.error('Erro:', e.message);
}

return [{ json: { projects: projects.filter(p => p.isValid) } }];

return [
  {
    json: {
      message: 'Projeto criado com sucesso!',
      projectId: $input.first().json.projectId
    }
  }
];
